    m.impl(\"instance_norm_custom\", &instance_norm_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def(\"instance_norm_custom\", &instance_norm_impl_npu, \"InstanceNorm2d (InstanceNormCustom on NPU)\");
}
